SELECT id, template_id, title, status, progress, due_date, created_at, updated_at
FROM task
WHERE id = #{id}

SELECT id, template_id, title, status, progress, due_date, created_at, updated_at FROM task WHERE 1=1
AND template_id = #{templateId}
AND status = #{status}
AND (title LIKE CONCAT('%', #{keyword}, '%'))
ORDER BY created_at DESC
